const lang = getLanguageFromURL(Astro.url.pathname);
const fallbackSlug = (slug: string) => 'en/' + stripLangFromSlug(slug);

const recipes = Astro.props.slugs.map((slug) => {
	let isFallback = lang !== 'en' && slug.startsWith('en/');
	let entry = recipePages.find((recipe) => recipe.id === slug);
	if (!entry) {
		isFallback = true;
		entry = recipePages.find((recipe) => recipe.id === fallbackSlug(slug));
	}
	if (!entry) {
		throw new Error(`Could not find entry for slug "${slug}"`);
	}
	return { slug, isFallback, title: entry.data.title, altTitle: entry.data.altTitle };
});

const isList = recipes.length > 1;
const labelKey = isList ? 'recipesLink.plural' : 'recipesLink.singular';
const firstRecipe = recipes[0];
if (!firstRecipe) {
	throw new Error('No slugs passed to `<RecipeLinks>` component. Make sure you pass at least one.');
}

const assetHmrPlugin = () => {
  return {
    name: 'asset-hmr-plugin',
    configureServer(server) {
      // Watch for changes in the dist directory
      const watcher = server.watcher

      // Add dist directory to the watcher
      watcher.add(path.resolve('./dist'))

      // Watch for the reload trigger files
      watcher.on('change', (filePath) => {
        if (filePath.includes('.reload-trigger') || filePath.includes('reload-')) {
          // Force reload all clients
          server.ws.send({ type: 'full-reload' })
        }
      })

      // Watch for asset changes
      watcher.on('add', (filePath) => {
        if (filePath.startsWith(path.resolve('./dist'))) {
          // Force reload all clients
          server.ws.send({ type: 'full-reload' })
        }
      })
    }
  }
}

export const POST: APIRoute = async ({ request, locals }) => {
	const { emdash, user } = locals;

	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;

	try {
		const body = await parseBody(request, commentBulkBody);
		if (isParseError(body)) return body;

		// Bulk delete requires ADMIN, bulk status change requires EDITOR
		if (body.action === "delete") {
			const denied = requirePerm(user, "comments:delete");
			if (denied) return denied;
		} else {
			const denied = requirePerm(user, "comments:moderate");
			if (denied) return denied;
		}

		const result = await handleCommentBulk(emdash.db, body.ids, body.action);

		return unwrapResult(result);
	} catch (error) {
		return handleError(error, "Failed to perform bulk operation", "COMMENT_BULK_ERROR");
	}
};

export const GET: APIRoute = async ({ params, request, locals }) => {
	const { emdash, user } = locals;
	const name = params.name!;

	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;

	const denied = requirePerm(user, "menus:read");
	if (denied) return denied;

	const localeQ = parseQuery(new URL(request.url), localeFilterQuery);
	if (isParseError(localeQ)) return localeQ;

	try {
		// Look up any menu row matching the name so we can get its translation_group.
		const anchor = await handleMenuGet(emdash.db, name, { locale: localeQ.locale });
		if (!anchor.success) return unwrapResult(anchor);
		const result = await handleMenuTranslations(emdash.db, anchor.data.id);
		return unwrapResult(result);
	} catch (error) {
		return handleError(error, "Failed to fetch menu translations", "MENU_TRANSLATIONS_ERROR");
	}
};

export const PUT: APIRoute = async ({ params, request, locals }) => {
	const { emdash, user } = locals;
	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;
	const db = emdash.db;
	const { id } = params;

	const denied = requirePerm(user, "redirects:manage");
	if (denied) return denied;

	if (!id) {
		return apiError("VALIDATION_ERROR", "id is required", 400);
	}

	try {
		const body = await parseBody(request, updateRedirectBody);
		if (isParseError(body)) return body;

		const result = await handleRedirectUpdate(db, id, body);
		invalidateRedirectCache();
		return unwrapResult(result);
	} catch (error) {
		return handleError(error, "Failed to update redirect", "REDIRECT_UPDATE_ERROR");
	}
};

