for (const post of blog) {
	if (post.data.password) {
		feedItems.push({
			title: post.data.title,
			pubDate: post.data.published,
			description: post.data.description || "",
			link: url(`/posts/${post.id}/`),
			content: i18n(I18nKey.passwordProtectedRss),
		});
		continue;
	}
	const { Content } = await render(post);
	const rawContent = await container.renderToString(Content);
	const cleanedContent = stripInvalidXmlChars(rawContent);
	feedItems.push({
		title: post.data.title,
		pubDate: post.data.published,
		description: post.data.description || "",
		link: url(`/posts/${post.id}/`),
		content: sanitizeHtml(cleanedContent, {
			allowedTags: sanitizeHtml.defaults.allowedTags.concat(["img"]),
		}),
	});
}

export const PATCH: APIRoute = async ({ params, request, locals }) => {
	const { emdash, user } = locals;
	const denied = requirePerm(user, "schema:manage");
	if (denied) return denied;

	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;

	const slug = params.slug;
	if (!slug) return apiError("MISSING_PARAM", "Field slug is required", 400);

	const body = await parseBody(request, bylineFieldUpdateBody);
	if (isParseError(body)) return body;

	const result = await handleBylineFieldUpdate(emdash.db, slug, {
		label: body.label,
		required: body.required,
		translatable: body.translatable,
		// `null` clears the stored validation; `undefined` leaves it as-is.
		// The zod schema makes `validation` itself optional, so an absent
		// key reaches the handler as `undefined`.
		validation: body.validation,
		sortOrder: body.sortOrder,
	});
	return unwrapResult(result);
};

export const PUT: APIRoute = async ({ params, request, locals }) => {
	const { emdash, user } = locals;

	if (!emdash?.db) {
		return apiError("NOT_CONFIGURED", "EmDash is not initialized", 500);
	}

	if (!user || user.role < Role.ADMIN) {
		return apiError("FORBIDDEN", "Admin privileges required", 403);
	}

	const clientId = params.id;
	if (!clientId) {
		return apiError("VALIDATION_ERROR", "Client ID is required", 400);
	}

	try {
		const body = await parseBody(request, updateClientSchema);
		if (isParseError(body)) return body;

		const result = await handleOAuthClientUpdate(emdash.db, clientId, body);
		return unwrapResult(result);
	} catch (error) {
		return handleError(error, "Failed to update OAuth client", "CLIENT_UPDATE_ERROR");
	}
};

